  'person',
  '{"document_kind":"tour_product_full_page_v1","schema_version":7,"slug":"jeju-hydrangea-festival-tour-southwest-route","locale":"en","product_id":"jeju-hydrangea-festival-tour-southwest-route","seo":{"pageTitle":"Jeju Southwest Hydrangea Festival Day Tour | AtoC Korea","metaDescription":"Summer-only southwest Jeju day tour: Hyeopjae Beach, Hallim Park hydrangea festival, Jusangjeolli Cliff, Cheonjeyeon Falls, Camellia Hill, Osulloc tea fields.","ogImage":"https://images.unsplash.com/photo-1559948638-e8e07b62b9c1?w=1920&q=80","primaryKeywords":["Jeju hydrangea festival tour","Jeju summer flower tour","Camellia Hill hydrangea","Jeju southwest day tour","Hydrangea Sansumok tour"],"title":"Jeju Hydrangea Festival Tour · Southwest Route · Summer-Only Small-Group Day Tour"},"catalog_card":{"slug":"jeju-hydrangea-festival-tour-southwest-route","title":"Jeju Southwest Hydrangea Festival Small Group Tour","subtitle":"Beach to columnar cliff to hydrangea tunnel.","region":"Southwest Jeju","duration":"9 hours","stopsCount":6,"rating":0,"reviewCount":0,"badges":["Summer Only","Hydrangea Season","Southwest Jeju"],"heroImage":"https://images.unsplash.com/photo-1559948638-e8e07b62b9c1?w=1920&q=80","thumbnail":"https://images.unsplash.com/photo-1559948638-e8e07b62b9c1?w=600&q=80","priceLabel":"Price varies — confirm at booking","shortCardDescription":"Summer-only southwest Jeju route — emerald beach, hydrangea festival gardens, UNESCO columnar cliff, three-tier waterfall, hydrangea tunnel, and tea fields.","tags":["summer_only","hydrangea_season","southwest_jeju"]},"headlineLine1":"Hydrangea, columnar cliff, and tea fields","headlineLine2":"in one southwest Jeju summer day","price":{"amountLabel":"","currency":"USD","per":"person"},"hero":{"imageUrl":"https://images.unsplash.com/photo-1559948638-e8e07b62b9c1?w=1920&q=80","imagePosition":"center 35%","tagline":"Beach to columnar cliff to hydrangea tunnel.","pills":["Summer Only","Hydrangea Season","Southwest Jeju"],"meta":{"duration":"9 hours","region":"Southwest Jeju","stops":"6 stops","rating":0,"ratingStars":0}},"subnavItems":[{"id":"overview","label":"Overview"},{"id":"itinerary","label":"Itinerary"},{"id":"practical","label":"Practical"},{"id":"reviews","label":"Reviews"},{"id":"booking","label":"Booking"}],"glanceItems":[{"icon":"camera","label":"Photo Value","value":"Very High"},{"icon":"calendar","label":"Season","value":"Jun - Mid Jul"},{"icon":"users","label":"Group Size","value":"Small Group"},{"icon":"clock","label":"Duration","value":"9 hours"},{"icon":"map-pin","label":"Region","value":"Southwest Jeju"},{"icon":"footprints","label":"Walking","value":"Easy to moderate"}],"galleryItems":[{"id":"g1","type":"photo","src":"https://images.unsplash.com/photo-1559948638-e8e07b62b9c1?w=1200&q=80","alt":"Hydrangea blooms at Hallim Park","caption":"Hydrangea blooms at Hallim Park","location":"Hallim Park","atmosphere":"Hydrangea festival in full bloom"},{"id":"g2","type":"photo","src":"https://images.unsplash.com/photo-1583416750470-965b2707b355?w=1200&q=80","alt":"Hydrangea tunnel at Camellia Hill","caption":"Hydrangea tunnel at Camellia Hill","location":"Camellia Hill","atmosphere":"Hydrangea tunnel walk"},{"id":"g3","type":"photo","src":"https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=1200&q=80","alt":"Hyeopjae Beach turquoise water","caption":"Hyeopjae Beach turquoise water","location":"Hyeopjae Beach","atmosphere":"Emerald water and white sand"},{"id":"g4","type":"photo","src":"https://images.unsplash.com/photo-1518837695005-2083093ee35b?w=1200&q=80","alt":"Jusangjeolli columnar basalt cliff","caption":"Jusangjeolli columnar basalt cliff","location":"Jusangjeolli Cliff","atmosphere":"Columnar basalt formation"},{"id":"g5","type":"photo","src":"https://images.unsplash.com/photo-1542273917363-3b1817f69a2d?w=1200&q=80","alt":"Cheonjeyeon three-tier waterfall","caption":"Cheonjeyeon three-tier waterfall","location":"Cheonjeyeon Falls","atmosphere":"Three-tier waterfall"},{"id":"g6","type":"photo","src":"https://images.unsplash.com/photo-1556761175-5973dc0f32e7?w=1200&q=80","alt":"Osulloc green tea fields","caption":"Osulloc green tea fields","location":"Osulloc Tea Museum","atmosphere":"Endless green tea fields"}],"itineraryStops":[{"number":1,"time":"09:30","duration":"40 min","name":"Hyeopjae Beach","category":"West-coast emerald beach + Biyangdo Island view","description":"**Hyeopjae Beach (협재 해수욕장)** is one of **Jeju''s Top 3 west-coast beaches** and broadly ranked among the island''s overall **Top 10 beaches**, defined by its **distinctive silvery-white sand** — formed from **crushed seashells + coral fragments mixed with fine sand**, producing a luminescence rare on the Korean Peninsula. The beach forms a **9 km shoreline** when paired with its **twin-beach companion Geumneung Beach (immediately south, walkable along the same shore, less crowded)** — the two-beach pairing is one of the catalog''s signature photographic windows. The signature view is **Biyangdo Island (비양도)** — a **1.2-km offshore volcanic island with ~200 permanent residents**, accessible by **20-minute ferry from Hallim Port**. Biyangdo is undergoing **Korea''s first carbon-free island certification process**, an environmental policy showcase. The beach''s **emerald-turquoise water** comes from the shallow coral-sand seabed, and at **low tide, tidal pools reveal hermit crabs, small shrimp, and juvenile fish** — Biyangdo can appear ''walkable'' across the shallow expanse. **Pine forest backdrop (Songlim)** behind the beach offers free camping ground and shaded walking paths. Behind the dunes runs Jeju''s most-developed **west-coast café strip** — concentrated cafe + restaurant + boutique architecture catering to domestic tourism. **Sunset behind Biyangdo over emerald water** is the visual signature and the catalog''s premier west-coast sunset framing. **FREE admission**; **lifeguarded swim period July 1 – August 31**; ramp-style **wheelchair access** at multiple beach points; public restrooms + changing rooms + showers + equipment rentals year-round. Adjacent **Hallim Park** (botanical garden + lava caves + folk village, separate ₩10,000 admission, 1.5 km away) is occasionally substituted in winter.","image":"https://images.unsplash.com/photo-1507525428034-b723cf961d3e","highlights":["**Top 3 west-coast Jeju beaches / Top 10 overall** — emerald-turquoise water + silvery sand","**Distinctive silvery-white sand** — crushed seashells + coral fragments","**9 km shoreline** when paired with twin-beach **Geumneung Beach** (less crowded, walkable)","**Biyangdo Island** — 1.2 km offshore, ~200 residents, **Korea''s first carbon-free island certification**","**Sunset behind Biyangdo** — catalog''s premier west-coast sunset framing","**Pine forest (Songlim) backdrop** with free camping ground","**Tidal pools at low tide** — hermit crabs, shrimp, juvenile fish; Biyangdo ''walkable'' optical effect","**Lifeguarded swim period July 1 – August 31**; wheelchair-accessible ramp at multiple points","**Most-developed west-coast café strip** behind the beach"],"timeUsed":["Coach arrival + parking — ~5 min","Main beach walk + photo windows — ~20 min","Geumneung twin-beach extension (optional) — ~15 min","Cafe strip break + snacks — ~15 min","Sunset photography vantage point — ~5 min"],"whyOnRoute":"**West-coast beach opener — and the natural pre-anchor for Hallim Park.** Three southwest-route reasons Hyeopjae is the morning opener at 09:30. (1) **Geographic pairing with Hallim**: Hyeopjae Beach sits **a 5-minute walk north of Hallim Park''s main gate** — pairing them as a single morning duo is the local-operator standard and converts what would otherwise be ''two stops within 1 km'' into a coherent Hyeopjae→Hallim arc. Visiting Hyeopjae first preserves a **clean, uncrowded beach morning** before the 10:30 Hallim gate-opening tour-bus rush. (2) **Light timing**: Hyeopjae''s signature emerald-turquoise water + silvery-white seashell-sand contrast is most photogenic in the **9:30–10:30 morning window** when the sun is high enough to saturate the colors but the late-morning haze hasn''t yet built up off the shoreline. (3) **Biyangdo Island anchor for the day''s signature wide-landscape photo**: Biyangdo (1.2 km offshore, ~200 residents) sits as the day''s first and only **horizon-island silhouette** — every subsequent stop is inland or coastal-cliff, so locking the Biyangdo wide-shot as the morning''s first deliverable gives the day''s photo set its required landscape breadth before pivoting into the garden + columnar-cliff + tea-fields close.","_poi_meta":{"poi_key":"hyeopjae_beach","kb_version":"1.20","verified_date":"2026-04-29","sources":["VisitJeju — Hyeopjae Beach + Biyangdo Island official listings","Jeju Special Self-Governing Province — Top Jeju beaches ranking + amenity registry","Korea Maritime + Ports Office — Hallim Port ferry schedule to Biyangdo","Jeju Tourism Organization — west-coast sunset photography spots registry","Hallim-eup local cultural office — Geumneung twin-beach pairing documentation"]}},{"number":2,"time":"10:30","duration":"120 min","name":"Hallim Park (Hydrangea Festival)","category":"Hydrangea anchor + 9 themed gardens + 2 lava-tube caves","description":"**Hallim Park (한림공원, founded 1971)** is the southwest coast''s anchor botanical park — a **~99,000 m² (originally 100,000 pyeong / 330,580 sqm) garden complex** that **founder Song Bong-gyu transformed from a sandy wasteland into a green paradise** by importing soil and planting palm seeds across a half-century. The park draws **~1.2 million visitors annually** and organizes its space into **nine themed gardens**: the **Subtropical Botanic Garden**, the **Palm Tree Avenue**, the **Wild Grass and Flower Garden**, the **Hyeopjaegul + Ssangyonggul Caves**, the **Jeju Stone and Bonsai Garden**, the **Jae-Am Folk Village** (Joseon-era stone-walled hanok with on-site Dolharubang Restaurant), the **Bird Garden**, the **Jeju Stone Exhibit Hall**, and the **Water Garden**. Hallim''s defining structural decision is its **monthly festival calendar** — **January Daffodil → February Plum Flower → March Tulip → April Cherry Blossom → May Wild Flower / Bougainvillea → **June Hydrangea** → July–September Lotus + Water Lily → October Cosmos / Pink Muhly → November Chrysanthemum → December Camellia** — a 12-month cycle that guarantees a **named active festival every month of the year**. The park''s two geological landmarks are **Hyeopjaegul Cave (~200m × 10m × 5m, ~25 million years old)** and **Ssangyonggul Cave (~400m × 6m × 3m, ''Two Dragons'')** — both part of the same **17 km lava-tube system** but uniquely classified as **''two-dimensional caves''** because lava-tube walls were later coated with **limestone (calcium carbonate) leached from shells in the soil above**, producing the rare global combination of **lava-tube morphology + limestone stalactites/stalagmites** in a single cave system. Cave temperature holds at **17–18°C year-round**, making them natural summer refuges. The park''s guest list reflects its diplomatic stature: former Chinese President Jiang Zemin, former Japanese Prime Minister Nakasone Yasuhiro, former Korean President Kim Dae-jung, former Samsung Chairman Lee Kun-hee, and former Hyundai Group Chairman Chung Ju-yung have all visited.","image":"https://images.unsplash.com/photo-1599598425947-5219dc1d4e93","highlights":["**Founded 1971** by Song Bong-gyu — sandy wasteland transformed into a green paradise","**~99,000 m² / 80 acres** — 9 themed gardens + ~1.2 million visitors per year","**June Hydrangea Festival** — the park''s signature June anchor","**Monthly festival calendar** — named active festival every month of the year","**Hyeopjaegul Cave** (~200m × 10m × 5m, ~25 million years old) — lava-tube + limestone stalactites","**Ssangyonggul Cave** (''Two Dragons'', ~400m × 6m × 3m) — branching paths cave system","**''Two-dimensional caves''** — only lava-tube + limestone caves in the world (17 km system)","Cave temp **17–18°C year-round** — natural summer refuge","Diplomatic guest list: **Jiang Zemin, Nakasone, Kim Dae-jung, Lee Kun-hee, Chung Ju-yung**"],"timeUsed":["Park entry + ticket + welcome — 10 min","Subtropical / Palm / Wild Flower gardens — 30 min","**Hyeopjaegul + Ssangyonggul caves** (cool down + photos) — 35 min","Hydrangea garden + Jae-Am Folk Village — 35 min","Restroom + park exit — 10 min"],"whyOnRoute":"**The day''s hydrangea anchor — and the southwest route''s identity-defining stop.** Four reasons Hallim is the late-morning anchor at 10:30 with a generous 120-min dwell. (1) **Hydrangea season alignment**: June is the Hallim Park monthly-calendar **Hydrangea Festival month** — Hallim is the first of the day''s three hydrangea-coded venues (Hallim morning anchor → Camellia Hill afternoon hydrangea tunnel → Osulloc tea-garden afternoon green tone). (2) **Cave-as-weather-fallback**: the **Hyeopjaegul + Ssangyonggul cave pairing** gives the day a guaranteed **indoor-equivalent refuge** against unpredictable southwest-Jeju June weather (June is Korea''s pre-monsoon shoulder; afternoon thundershowers happen ~1 in 4 days). The 17–18°C cave temperature also serves as the day''s **mid-morning cool-down** before the warm midday transit. (3) **120-min dwell justification**: Hallim''s 9 themed gardens + 2 caves cannot be done meaningfully in less than 90 minutes — the 120-min slot accounts for **slow-walking in the caves** (uneven lava-tube floors), **photo dwell at hydrangea field**, and **typical 5-min queue at the cave entrance** during peak season. (4) **Operational pairing with Hyeopjae**: because Hyeopjae sits 5 min walk away, the morning Hyeopjae→Hallim arc consumes 160 min total but only 5 min of vehicle transit — extracting maximum guest value from the operator''s morning fuel budget.","_poi_meta":{"poi_key":"hallim_park","kb_version":"1.21","verified_date":"2026-04-29","sources":["https://english.visitkorea.or.kr/svc/whereToGo/locIntrdn/rgnContentsView.do?vcontsId=104761 — Hallim Park, Visit Korea (KTO)","http://jejucvb.com/Hallim — Jeju CVB official Unique Venue page (founder Song Bong-gyu + diplomatic guest list)","https://www.tripadvisor.com/Attraction_Review-g297885-d2204895-Reviews-Hallim_Park-Jeju_Jeju_Island.html — Tripadvisor Hallim Park (annual visitors + 9 themed gardens + monthly festival calendar)","https://www.trazy.com/experience/detail/hallim-park-jeju-ticket — Trazy Hallim Park ticket page (cave system + ''two-dimensional caves'' classification + Natural Monument designation)","https://www.expatolife.com/hallim-park-jeju-island-south-korea/ — Expatolife Hallim Park guide (cave dimensions + 17 km lava-tube system)"]}},{"number":3,"time":"12:35","duration":"60 min","name":"Lunch (Southwest Jeju)","category":"Operational stop — local southwest-Jeju lunch","description":"**Lunch is at a local Jeju-style restaurant in the Hallim / Aewol-tail / Andeok corridor**, selected from a vetted shortlist of family-run establishments that the operator has approved for **English-friendly menus, dietary accommodation (vegetarian + halal-friendly chicken/seafood options on request), and west-coast Jeju specialties** at fair group pricing. Typical lunch options include **galchi-jorim (braised silver hairtail)**, **heuk-dwaeji bulgogi (Jeju black pork bulgogi)**, **mom-guk (Jeju seaweed-pork soup)**, and **bibimbap with seasonal namul**. **Mom-guk in particular is a southwest-Jeju regional specialty** that doesn''t appear on east-coast tours. Like the east-route lunch, the exact restaurant is selected the day before based on group size, dietary requests, and kitchen availability — guests are notified at the morning briefing. **Lunch cost is at guests'' own expense** (~₩12,000–₩18,000 per person) and is **not included** in the tour fee. Beverages and rice/banchan refills are always included with the meal.","image":"https://images.unsplash.com/photo-1414235077428-338989a2e8c0","highlights":["**Southwest-Jeju local restaurant** — Hallim / Aewol-tail / Andeok corridor","Vetted shortlist: **English-friendly menus** + dietary accommodation","Signature options: **galchi-jorim, heuk-dwaeji bulgogi, mom-guk (regional), bibimbap**","**Mom-guk** = west-Jeju regional specialty (seaweed-pork soup) not on east tours","**Lunch at guests'' own expense** (~₩12,000–₩18,000/person, not included)","Vegetarian + halal-friendly options on request"],"timeUsed":["Arrival + seating — 5 min","Order + dietary check — 5 min","Meal — 35 min","Settle bill + restroom — 10 min","Boarding + departure — 5 min"],"whyOnRoute":"**Operational midday stop**, locked at 12:35 to bridge the morning Hyeopjae+Hallim anchor (120 min Hallim runs into early-lunch zone) and the afternoon Jusangjeolli/Cheonjeyeon + Camellia Hill arc. The 60-min slot also serves as a **buffer absorber** — if the Hallim cave queue runs long during peak-season weekends, the lunch window compresses to 50 min without disrupting the 13:50 columnar-cliff target.","_poi_meta":{"poi_key":"OPS_lunch","kb_version":"1.20","verified_date":"2026-04-29","sources":[]}},{"number":4,"time":"13:50","duration":"75 min","name":"Jusangjeolli Cliff & Cheonjeyeon Falls","category":"Compound stop — Natural Monument 443 columnar joints + Natural Monument 378 three-tier waterfall","description":"**This is a paired stop** combining two of Jungmun''s signature Natural Monuments into a single ~75-min walking arc — the operator''s standard-practice southwest treatment for two anchors that sit a **7-min drive (~3 km)** apart. Stop A is **Daepo Jusangjeolli Cliff (대포 주상절리, ''Daepo Columnar Joints'')** — designated **Natural Monument No. 443 on January 6, 2005** (the most recent Jeju coastal Natural Monument designation), a **1.75 km coastal cliff face of polygonal black basalt columns** formed when **Hallasan-eruption lava cooled rapidly against Pacific seawater ~140,000–250,000 years ago**, fracturing the basalt into **hexagonal and pentagonal columns up to 30–40 m tall**. The site is part of the **Jeju Volcanic Island and Lava Tubes UNESCO Global Geopark (2010)**. Wave heights during peak south swells reach **20+ meters** crashing against the column base, producing the iconic Jeju basalt-cliff seascape. Stop B is **Cheonjeyeon Falls (천제연, ''Pond of the Emperor of Heaven'')** — designated **Natural Monument No. 378 (1993)** for its rare ecological combination of a three-tier waterfall + dense subtropical-warm-temperate transition forest. The name traces to a **Joseon-era Daoist legend that seven heavenly nymphs (선녀, *seonnyeo*) descended nightly to bathe in the upper pond**. The site''s signature visual is **Seonimgyo Bridge (선임교, ''Seven Nymph Bridge'')** — a 128-m-long arched footbridge with seven nymph statues facing the upper falls. The **operator''s pairing logic**: visiting both as a single 75-min stop preserves the day''s Hallim+Camellia+Osulloc floral pacing without splitting it across two transits, and the **Jusangjeolli cliff geology + Cheonjeyeon waterfall+forest layering** gives the southwest route its required **non-floral counterpoint** to the day''s three garden anchors.","image":"https://images.unsplash.com/photo-1606112219348-204d7d8b94ee","highlights":["**Compound stop** — 2 Natural Monuments paired in one 75-min walk (3 km / 7-min drive between)","**Daepo Jusangjeolli — Natural Monument No. 443 (2005)** — most recent Jeju coastal NM","**1.75 km coastal cliff** of hexagonal/pentagonal black basalt columns up to 30–40m tall","Part of **Jeju UNESCO Global Geopark (2010)** — formed ~140,000–250,000 years ago","**Wave heights up to 20m+** during peak south swells crashing against columns","**Cheonjeyeon Falls — Natural Monument No. 378 (1993)** — three-tier waterfall + transition forest","**Seven Nymphs (선녀) Joseon Daoist legend** — heavenly nymphs descended to bathe nightly","**Seonimgyo Bridge (선임교)** — 128-m arched footbridge with 7 nymph statues","**Floral counterpoint** — the day''s only non-garden geological + waterfall stop"],"timeUsed":["Arrive Jusangjeolli + entry — 5 min","Jusangjeolli cliff observation deck + photos — 25 min","Drive to Cheonjeyeon (~7 min) + restroom — 12 min","Cheonjeyeon Seonimgyo Bridge + upper-pond viewpoint — 25 min","Cheonjeyeon exit + boarding — 8 min"],"whyOnRoute":"**The day''s geological + waterfall counterpoint to the three-garden floral arc.** Three southwest-route reasons this compound stop sits at 13:50. (1) **Geographic necessity**: Jusangjeolli + Cheonjeyeon are both in **Jungmun (~3 km apart)** — either both go in or both stay out. Going in is necessary because they are the **only Natural Monuments on the day''s path** (alongside the Black Pig at Hueree on the sister tour) and provide the day''s required UNESCO-Geopark anchor. (2) **Pacing counterweight**: without this stop, the southwest tour collapses into a garden-only sequence (Hallim hydrangea → Camellia Hill hydrangea → Osulloc tea) that loses visual variety after stop 2. The columnar cliff seascape + three-tier waterfall gorge give the afternoon the visual palette breadth that makes it a complete ''southwest Jeju day'' rather than a flower-only tour. (3) **Compound efficiency**: pairing both as 75-min stop frees up **45+ min** vs. visiting each as separate ~60-min stops — that surplus is what funds Hallim''s 120-min anchor dwell + Camellia Hill''s afternoon photo time.","_poi_meta":{"poi_key":"daepo_jusangjeolli_cliff","secondary_poi_keys":["cheonjeyeon_falls"],"kb_version":"1.21","verified_date":"2026-04-29","is_compound_stop":true,"compound_stop_note":"Paired stop — Jusangjeolli + Cheonjeyeon visited within a single 75-min transit-shared window. Primary KB anchor `daepo_jusangjeolli_cliff` (facts in poi_knowledge_base_v1.21.json), secondary `cheonjeyeon_falls`.","sources":["https://english.visitkorea.or.kr/svc/whereToGo/locIntrdn/rgnContentsView.do?vcontsId=78866 — Jusangjeolli Cliff, Visit Korea (KTO)","https://english.visitkorea.or.kr/svc/whereToGo/locIntrdn/rgnContentsView.do?vcontsId=78918 — Cheonjeyeon Falls, Visit Korea (KTO)","https://en.wikipedia.org/wiki/Jeju_Volcanic_Island_and_Lava_Tubes — UNESCO Global Geopark (2010) overview","https://heritage.unesco.or.kr/jeju-volcanic-island-and-lava-tubes/ — Korea National Heritage Service Jeju Volcanic listing","https://www.peek.com/seogwipo-si-jeju-do-south-korea/r0an9mv/jeju-island-hydrangeas-a-floral-paradise/a067e9nx — Peek ''Jeju Island Hydrangeas'' tour itinerary documenting the compound-stop pattern"]}},{"number":5,"time":"15:15","duration":"75 min","name":"Camellia Hill (Hydrangea Tunnel)","category":"Hydrangea tunnel + 172,000 m² largest camellia arboretum in the East","description":"**Camellia Hill (카멜리아힐, Jeju Camellia Arboretum)** is a **172,000 m² botanical garden** in Andeok, **the largest camellia arboretum in the East** by acreage and species count: **6,000 camellia trees representing over 500 species sourced from 80 countries**, accumulated over **30+ years** of curation by founder Yang Jong-mun. The garden''s signature is its **year-round flowering calendar**, deliberately engineered so that visiting in any season produces a different color palette: **November–March = camellia peak** (red, pink, white, cream-beige varieties — the garden''s namesake season); **March–May = cherry blossoms + tulips + late camellias** layered together in dense color mass; **June–August = hydrangeas** (both outdoor stands and a climate-controlled greenhouse showing year-round display); **September–October = fall foliage + late-season bloomers**. Walking paths thread through themed sections — **European Garden, Korean Native Forest Section, Cherry Blossom Walk, Hydrangea Field** — connected by a winding 2.5-km loop that takes ~60–75 min to complete at a leisurely pace. Notable architectural moment: a **glass greenhouse + gallery + cafe** complex at the entrance, which serves as both indoor weather refuge (the only ~15% indoor portion of the visit) and a tea/coffee dwell space with garden views. **Drama filming credit**: variety show **''EXchange / Transit Love 3'' (환승연애)** featured Camellia Hill as the location of Ju-won and Yu-jeong''s memorable date scene — a draw for fans of the K-reality genre. **Open 365 days a year**; **no outdoor lighting** means the garden closes at sundown (winter ~17:00, summer ~19:00). Admission: **Adult ₩12,000 / Youth + Senior ₩10,000 / Child (4–11) ₩9,000 / FREE under 3**.","image":"https://images.unsplash.com/photo-1490750967868-88aa4486c946","highlights":["**172,000 m²** — largest camellia arboretum in the East","**6,000 trees / 500+ species from 80 countries** — accumulated 30+ years","**Year-round bloom calendar** — Nov–Mar camellias, Mar–May cherry + tulip, Jun–Aug hydrangea","**Themed sections**: European Garden, Korean Native Forest, Cherry Walk, Hydrangea Field","Glass **greenhouse + gallery + cafe** complex — indoor refuge (15% of visit)","**''EXchange / Transit Love 3''** filming location — Ju-won & Yu-jeong''s date scene","**Open 365 days**; closes at sundown (no outdoor lighting)","Admission **₩12,000 adult / ₩10,000 youth+senior / ₩9,000 child (4–11) / FREE under 3**","**~85% outdoor** garden walking — comfortable shoes recommended"],"timeUsed":["Parking + entrance + welcome — ~10 min","Camellia + featured-bloom section walk — ~25 min","European Garden + Hydrangea Field — ~20 min","Greenhouse + cafe break (optional) — ~15 min","Buffer / restroom — ~5 min"],"whyOnRoute":"**The afternoon''s hydrangea-tunnel anchor — and the day''s photographic centerpiece.** Three southwest-route reasons Camellia Hill is the afternoon-2 anchor at 15:15. (1) **Hydrangea Tunnel — Korea''s earliest blooming hydrangeas**: Camellia Hill houses **Korea''s earliest-blooming hydrangeas (early April indoor + outdoor full bloom from June)**, with the **Hydrangea Hall pergola tunnel** as the day''s definitive Instagram-anchor photo (giant blue/pink/purple hydrangea balls hanging above a covered walkway). The June 10–25 peak window aligns exactly with this tour''s seasonal positioning. (2) **Garden-pacing complementarity**: Camellia Hill''s **1.2 km / 0.75-mile walking loop** is gentler than Hallim''s 9-themed-garden complexity, making it the day''s **photo-immersive low-effort garden** after the morning''s higher-density Hallim anchor. The two gardens together build a **garden-pacing arc** (intensive Hallim → relaxed Camellia Hill) that wouldn''t work if reversed. (3) **Late-afternoon light**: the 15:15–16:30 window catches the **warm late-afternoon golden light** that flatters the hydrangea pinks and blues (midday flat light desaturates them, same logic as Hueree on the east route). Camellia Hill''s signature photographers''-mirror installation also captures golden-hour reflections from this slot. **Sister-route note**: this stop matches the afternoon timing of Hueree on the east route — both sister tours close their hydrangea anchor in late afternoon for matching sun angles.","_poi_meta":{"poi_key":"camellia_hill","kb_version":"1.20","verified_date":"2026-04-29","sources":["Camellia Hill official site (camelliahill.co.kr)","VisitJeju — Camellia Hill official listing","Andeok-myeon cultural tourism office","Korea Tourism Organization — Top Korean botanical gardens registry","Kakao TV / Wavve programming archive — ''EXchange / Transit Love 3'' filming locations"]}},{"number":6,"time":"16:45","duration":"60 min","name":"Osulloc Tea Museum & Tea Fields","category":"Amorepacific tea-culture flagship + green-tea fields finale","description":"**O''Sulloc Tea Museum (오설록 티 뮤지엄, ''오설록'' meaning ''meeting snow + green'')** is the tea-culture flagship of **Amorepacific Corporation** — Korea''s largest beauty company. Founder **Suh Sung-whan personally pioneered the project in 1979**, reclaiming volcanic ash farmland on Jeju''s Seogwang plateau when conventional wisdom held tea couldn''t be grown commercially in Korea. Today the **Seogwang Dawon plantation (서광다원)** is **Korea''s largest green-tea field**, producing **~700 tonnes annually** across Amorepacific''s three Jeju estates. The museum building **opened 2001** in the plantation''s heart and was named to **designboom''s Top 10 art museums** for its minimalist green-roofed pavilion-amid-tea-rows design. **FREE admission**, daily **09:00–18:00**, ~**2 million annual visitors**. The visit splits naturally into three segments: **(1) Museum interior** — tea production process, antique tea-ware collection from Tang dynasty (618–907 CE) onward, and rooftop observation deck with panoramic plantation view; **(2) Tea House cafe** — signature **green tea rolling cake (오설록 롤케이크)** and **green tea ice cream** served from the tea-leaf harvest year directly; **(3) Plantation walking paths** — gravel rows between tea bushes, popular for sunset photography at the western edge. **Innisfree Jeju House** (Amorepacific''s natural cosmetics brand) is a **5-minute walk** for guests interested in the broader brand ecosystem — also free admission with optional tangerine soap DIY workshop (₩15,000). The museum building itself, designed by Korean architect **Mass Studies (Cho Min-suk)**, takes a deliberately low-profile horizontal form that mirrors the tea-row geometry rather than competing with the agricultural landscape — the architectural deference earning it both the designboom Top 10 listing and ongoing use as a case study in Korean contemporary museum design. Optional add-on: the **Osulloc Tea Class (₩30,000 per person, 60 min, advance booking required)** — guided tea-flight tasting with brewing technique demonstration on Korean ceramics, available daily **10:00–16:00**, English-speaking instruction on Wed/Sat sessions.","image":"https://images.unsplash.com/photo-1495474472287-4d71bcdd2085","highlights":["**Amorepacific** flagship — Korea''s largest beauty company; founder Suh Sung-whan pioneered Jeju tea **1979**","**Seogwang Dawon = Korea''s largest green-tea field**; ~700 tonnes annual production","Museum **opened 2001** — designboom Top 10 art museums (architecture)","**FREE admission**, daily **09:00–18:00**, ~2 million annual visitors","Antique tea-ware collection spanning **Tang dynasty (618–907 CE)** to modern Korean Joseon ceramics","**Green tea rolling cake** + **green tea ice cream** = signature cafe items","**Innisfree Jeju House** 5-min walk — free, optional tangerine soap DIY ₩15,000","Plantation walking paths **best at golden hour (16:00–17:00)** for photography","Rooftop deck + ground-level rows give two distinct elevations for tea-row composition"],"timeUsed":["Parking + entrance — ~5 min","Museum interior + tea-ware collection — ~20 min","Tea House cafe (rolling cake + ice cream) — ~20 min","Plantation walking path — ~20 min","Optional Innisfree Jeju House visit — ~10 min"],"whyOnRoute":"**The day''s tea-culture finale — and the southwest route''s signature non-floral close.** Three reasons Osulloc closes the day at 16:45. (1) **Tea-color counterpoint to the day''s hydrangea palette**: after 4 garden/cliff stops in varying flower-heavy palettes, Osulloc''s **emerald-green tea-field rows + Innisfree Jeju House''s white-glass architecture** give the day''s photo set its closing color tone — saturated green that contrasts with the morning''s hydrangea blues/pinks. (2) **Indoor-finale + restroom-buffer**: Osulloc''s tea museum + cafe provide the day''s **only indoor late-afternoon stop** — guests can use the museum''s tea-tasting + ice-cream + restroom facilities to decompress before the **40-min westbound transit back to Jeju City**. The 60-min dwell is sized exactly to allow tea purchase + ice cream + 1 quick tea-field walk. (3) **Brand-cultural anchor**: Osulloc as the **Amorepacific tea flagship (founded 1979 by founder Suh Sung-whan)** ties the day''s tour back to one of Korea''s globally-recognized brands — a deliberate brand-cultural close that distinguishes this route from generic ''flower garden tours'' and gives the day a clear cultural-economic finale story.","_poi_meta":{"poi_key":"osulloc_tea_museum","kb_version":"1.20","verified_date":"2026-04-29","sources":["Amorepacific corporate history (amorepacific.com)","O''sulloc Tea Museum official site (osulloc.com)","designboom Top 10 art museums archival listing","Korea Tea Industry Association — production statistics","VisitJeju — Osulloc Tea Museum"]}}],"routeFlowStops":[{"name":"Hyeopjae","type":"origin","theme":"Beach"},{"name":"Hallim Park","type":"primary","theme":"Hydrangea"},{"name":"Lunch","type":"meal","theme":"Meal"},{"name":"Jusangjeolli + Cheonjeyeon","type":"primary","theme":"Geology + Falls"},{"name":"Camellia Hill","type":"primary","theme":"Hydrangea Tunnel"},{"name":"Osulloc","type":"return","theme":"Tea Culture"}],"routePhases":[{"phase":"Beach + Hydrangea festival","duration":"Stops 1–2","description":"Morning: Beach + Hydrangea festival"},{"phase":"Lunch","duration":"Stops 3","description":"Midday: Lunch"},{"phase":"Geology, hydrangea tunnel, tea","duration":"Stops 4–6","description":"Afternoon: Geology, hydrangea tunnel, tea"}],"routeShapeIntro":{"title":"How this summer day moves","subtitle":"Beach warm-up, hydrangea festival, lunch reset, then UNESCO geology, hydrangea tunnel, and tea fields. 08:30 to 17:30."},"whyTourWorks":{"bestFor":["First-time summer visitors","Couples and photo-focused travelers","Adult families","Travelers chasing peak hydrangea bloom"],"routeLogicSections":[{"title":"Pacing & structure","icon":"sun","iconBg":"bg-amber-50/80","iconColor":"text-amber-600","items":[{"label":"Beach as Light Opener","detail":"Hyeopjae as a low-intensity start lets the group settle before higher-attention bloom and geology sites."},{"label":"Two Hydrangea Stops, Different Formats","detail":"Hallim festival garden and Camellia tunnel give complementary compositions of the same flower — bookend morning and afternoon."},{"label":"Tea to Close","detail":"Osulloc closes calmly — culture and rest after the visual intensity of bloom and falls."}]},{"title":"Why this is summer-only","icon":"flower","iconBg":"bg-pink-50/80","iconColor":"text-pink-600","items":[{"label":"Hydrangea Window Late May - mid-July","detail":"Hydrangea blooms appear from late May, peak mid-June, and fade by mid-July. Outside this window the bloom stops lose their visual draw."},{"label":"Outside Window, Pick SW-Small","detail":"If your dates fall outside hydrangea season, our West & South year-round route covers the same region with year-round POIs (Hallasan, Osulloc, Aewol)."},{"label":"Camellia Hill is Not Camellia Season","detail":"Despite the name, this tour visits Camellia Hill specifically for hydrangea — actual camellias bloom in winter."}]},{"title":"Trade-offs honestly","icon":"info","iconBg":"bg-sky-50/80","iconColor":"text-sky-600","items":[{"label":"9 Hours Is Long","detail":"Six diverse stops in 9 hours — pace is fuller than east-small. Build energy with steady hydration."},{"label":"Some Stops Have Admission","detail":"Hallim Park (15,000 KRW) and Camellia Hill (10,000 KRW) admissions are paid on-site, not bundled into the tour price. Budget ≈30,000 KRW per person across all admissions (Jusangjeolli 2,000 + Cheonjeyeon 2,500 round it out)."},{"label":"Heat Can Be Real","detail":"June Jeju can hit 30°C+ at midday. Bring sun protection — most stops are outdoor."}]}],"lessIdealFor":["Off-season visitors (after mid-July)","Stroller-heavy groups (some uneven garden paths)","Travelers wanting mountain hiking"]},"practicalAccordionItems":[{"id":"pickup","title":"Pickup & drop-off","preview":"Hotel lobby pickup in Jeju City area","content":["Pickup from your hotel lobby between 08:00-08:30","Return drop-off by approximately 17:30-18:00","Hotel lobby pickup within Jeju City is free. Pickup from Seogwipo, Aewol, or Seongsan adds 70,000 KRW due to extra driving distance."]},{"id":"what-to-bring","title":"What to wear & bring","preview":"Sun protection, comfortable shoes, camera","content":["Comfortable walking shoes (multiple garden walks)","Sun protection — hat, sunscreen, sunglasses","Light layer for AC vehicle and tea house","Cash or card for lunch and admission"]},{"id":"season","title":"Hydrangea season window","preview":"June through mid-July","content":["Tour season: June 1 - July 15 (varies ±5 days year to year)","Peak window: June 25 - July 5 (best photographic conditions)","We update the booking page with year-specific bloom forecast in early May","If your travel dates fall outside the window, consider our West & South year-round route instead"]},{"id":"weather-policy","title":"Weather policy","preview":"Light rain operates; heavy rain reschedules","content":["Light rain: tour operates (hydrangea actually photographs well in soft rain)","Heavy rain: free rescheduling within season window","Outside-window cancellations follow the booking platform''s standard terms — see the booking confirmation for specifics."]},{"id":"inclusions","title":"What''s included","preview":"Transport, guide, and major admissions","content":["Hotel pickup and drop-off (Jeju City)","Air-conditioned van transport","Licensed English-speaking guide","Major admissions (Hallim Park, Camellia Hill, Jusangjeolli, Cheonjeyeon) are paid on-site, not bundled into the tour price","Lunch separate from base price"]}],"practicalWeatherStatic":{"today":{"label":"Summer weather guidance","temp":"Daytime ≈ 26–30 °C in hydrangea season (late May to mid-July, peak mid-June)","icon":"cloud-sun"},"tomorrow":{"label":"Live forecast available at the operator''s booking page","temp":"—","icon":"cloud"}},"seasonalVariations":[{"season":"Early Summer (Jun 1-24)","title":"Tour operates","description":"Hydrangea opens — gradually intensifying","icon":"flower"},{"season":"Peak (Jun 25 - Jul 5)","title":"Peak — books out fastest","description":"Peak hydrangea bloom across all gardens — best photographic conditions","icon":"flower"},{"season":"Late Bloom (Jul 6-15)","title":"Tour operates","description":"Hydrangeas still strong but starting to fade. Less crowded.","icon":"leaf"},{"season":"Outside window (Jul 16 - May 31)","title":"Off-season","description":"Out of season — our West & South year-round route recommended","icon":"info"}],"bookingTrustItems":[{"icon":"check-circle","title":"Licensed local","description":"Jeju-licensed guiding","iconBg":"bg-emerald-50/80","iconColor":"text-emerald-600"},{"icon":"calendar","title":"Season window flex","description":"Free rescheduling within bloom window","iconBg":"bg-pink-50/80","iconColor":"text-pink-600"},{"icon":"shield","title":"Weather guarantee","description":"Free reschedule on heavy rain","iconBg":"bg-sky-50/80","iconColor":"text-sky-600"}],"bookingSupportSteps":[{"timing":"Immediately","title":"Instant Confirmation","detail":"Booking confirmation with itinerary summary"},{"timing":"2 days before","title":"Weather Check-in","detail":"We monitor forecast and reach out if rebooking is recommended"},{"timing":"Day before","title":"Vehicle & Guide Info","detail":"Pickup time, vehicle plate, and guide name via WhatsApp"},{"timing":"Morning of","title":"Pickup Confirmation","detail":"Driver checks in 10 minutes before arrival"},{"timing":"During tour","title":"On-tour Support","detail":"Direct line to operations if anything comes up"},{"timing":"After tour","title":"Review & Followup","detail":"Optional review and follow-up"}],"staticQuestions":[{"id":"first-time","question":"Is this good for first-time visitors to Jeju?","answer":"Yes, if you''re visiting during hydrangea season (late May to mid-July, peak mid-June). Outside that window, our West & South year-round route covers the same region with year-round POIs."},{"id":"season-timing","question":"When exactly is hydrangea season?","answer":"Approximately late May to mid-July (peak mid-June), with peak typically in mid-June. We update the booking page with year-specific forecast in early May."},{"id":"rain","question":"What if it rains?","answer":"Light rain — we operate (hydrangea actually photographs beautifully in soft rain). Heavy rain — we offer free rescheduling within the season window."},{"id":"two-hydrangea-stops","question":"Why two hydrangea stops?","answer":"Hallim Park is an open festival garden; Camellia Hill is a tunnel format. Same flower, complementary compositions."},{"id":"kids","question":"Is this suitable for children?","answer":"Yes, age 6+. Walking is moderate at most stops; hydrangea gardens are family-friendly."},{"id":"seniors","question":"Is this ok for seniors?","answer":"Yes, mostly easy walking. Cheonjeyeon waterfall path has some stairs — can be skipped while group views Jusangjeolli."},{"id":"pickup-area","question":"Where do you pick up?","answer":"Hotel lobby pickup within Jeju City is free. Pickup from Seogwipo, Aewol, or Seongsan adds 70,000 KRW due to extra driving distance."},{"id":"lunch","question":"Is lunch included?","answer":"Lunch cost is separate. Expect 12,000-18,000 KRW per person."},{"id":"admission-fees","question":"Are admission fees included?","answer":"Admissions are not bundled by default. Budget ≈30,000 KRW per person: Hallim Park 15,000, Camellia Hill 10,000, Jusangjeolli 2,000, Cheonjeyeon 2,500, Osulloc free."},{"id":"tea-museum","question":"Is Osulloc included?","answer":"Yes — museum entry is free. The tea house is separate (optional purchase)."},{"id":"compare-west-south-year-round","question":"What''s the difference vs our West & South year-round route?","answer":"Different POIs and seasonality. Our West & South year-round route is year-round and visits Hallasan 1100, Osulloc, and Aewol. This tour is summer-only and adds Hyeopjae, Hallim, Jusangjeolli, Cheonjeyeon, Camellia Hill while keeping Osulloc as the closing stop."}],"guestReviews":[],"reviewsSummary":{"averageRating":0,"totalReviews":0,"ratingDistribution":[{"stars":5,"count":0,"percentage":0},{"stars":4,"count":0,"percentage":0},{"stars":3,"count":0,"percentage":0},{"stars":2,"count":0,"percentage":0},{"stars":1,"count":0,"percentage":0}],"highlights":[]},"sticky_booking_bar":{"note":"checkout_tour_id resolves at runtime from Supabase / env; not part of static JSONB.","price":{"amountLabel":"","currency":"USD","per":"person"}},"matching_profile":{"profile_version":6,"is_active":true,"product_id":"jeju-hydrangea-festival-tour-southwest-route","product_type":"small_group","route_type":"fixed_route","destination_region":"jeju","region_type":"jeju_southwest","vehicle_type":"minicoach","duration_hours":9,"region_tags":["jeju_west","jeju_southwest"],"theme_tags":["seasonal_flower","summer_flowers_hydrangea","garden","beach","geology","waterfall","tea_culture","iconic_landmarks","first_time_friendly","summer_only","photogenic"],"poi_tags":["hyeopjae_beach","hallim_park","jusangjeolli_cliff","cheonjeyeon_falls","camellia_hill","osulloc_tea_museum"],"pace_level":0.55,"walking_level":0.55,"scenic_level":0.95,"photo_level":1,"culture_level":0.6,"relax_level":0.85,"first_time_fit":0.85,"family_fit":0.95,"senior_fit":0.85,"couple_fit":1,"solo_traveler_fit":0.85,"active_traveler_fit":0.6,"adult_family_fit":0.95,"family_with_teens_fit":0.8,"young_kids_fit":0.85,"senior_active_fit":0.8,"senior_general_fit":0.8,"mobility_friendly_fit":0.8,"stroller_fit":0.7,"one_day_fit":0.8,"same_day_flight_fit":0.2,"rain_fit":0.55,"value_for_money_fit":0.7,"iconic_landmark_fit":0.85,"cafe_fit":0.6,"food_fit":0.6,"nature_fit":0.9,"beach_fit":0.55,"nightlife_fit":0.2,"shopping_fit":0.6,"no_shopping_fit":0.6,"local_culture_fit":0.6,"storytelling_fit":0.8,"unesco_fit":0.85,"intangible_heritage_fit":0.4,"indoor_ratio":0.2,"weather_sensitivity":0.85,"comfort_level":0.8,"budget_fit":0.6,"premium_fit":0.6,"small_group_fit":1,"private_fit":0.2,"bus_fit":1,"price_band":"mid","pickup_base":"jeju_city","return_time_band":"17:30-18:00","duration_band":"9h","min_recommended_age":6,"hard_constraints":{"avoidIf":["non_hydrangea_season_dates","tight_same_day_departure"],"notIdealFor":["very_low_mobility","stroller_heavy_if_waterfall_path_focus"]},"walking_notes":["Six stops with mostly flat garden walking.","Cheonjeyeon waterfall path has stairs (skippable).","Sun exposure is real in midsummer — bring sun protection.","Total walking moderate; longest single walk is Hallim Park hydrangea zones."],"keywords":["jeju hydrangea festival tour","jeju summer flower tour","hallim park hydrangea","camellia hill hydrangea tunnel","jeju west south day tour","jusangjeolli tour","cheonjeyeon falls tour","osulloc tea fields tour","jeju southwest small group","jeju june bloom tour"],"synonym_hints":["jeju summer bloom tour","hydrangea day trip jeju","jeju west south route","june jeju flower tour","jeju southwest hydrangea route","jeju seasonal hydrangea tour"],"seasonality":"summer_only_peak","pickup_base_normalized":"jeju","vehicle_type_legacy":"mini_coach","anchor_poi_keys":["camellia_hill","hyeopjae_beach","osulloc_tea_museum"],"profile_format":"small_group_fixed_itinerary","private_tour_fit":0.05,"fixed_itinerary_fit":1,"customizable_route_fit":0.05,"flexibility_fit":0.3,"first_time_jeju_fit":0.95,"south_jeju_fit":1,"southwest_jeju_fit":1,"central_jeju_fit":0.6,"north_jeju_fit":0.3,"east_jeju_fit":0.05,"west_jeju_fit":1,"west_coast_corridor_fit":1,"southwest_signature_fit":1,"jungmun_anchor_fit":1,"hallim_anchor_fit":1,"unesco_focused_tour_fit":0.5,"unesco_taste_fit":0.85,"unesco_geopark_fit":1,"unesco_world_heritage_fit":0.5,"natural_monument_fit":1,"natural_monument_anchor_count":2,"compound_stop_count":1,"hydrangea_festival_anchor_count":3,"summer_flowers_hydrangea_fit":1,"june_peak_floral_fit":1,"early_summer_jeju_fit":1,"named_seasonal_festival_anchor_count":2,"year_round_flower_park_fit":1,"garden_anchor_count":3,"hydrangea_tunnel_visit":true,"hydrangea_greenhouse_fallback_fit":0.5,"multi_garden_pairing_fit":1,"unesco_plus_floral_combo_fit":0.7,"tea_garden_finale_fit":1,"lava_tube_visit":true,"lava_tube_anchor_count":2,"two_dimensional_caves_fit":1,"columnar_joint_anchor_fit":1,"waterfall_anchor_fit":1,"tuff